const DEFAULT_CONSOLIDATION_MIN_INTERVAL_SECS: u64 = 3_600;

/// Current unix time in whole seconds.
pub fn now_unix() -> i64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_secs() as i64)
        .unwrap_or(0)
}

/// High-level facade over the graph store and the ingestion pipeline.
pub struct MindLeak {
    store: GraphStore,
    consolidation_min_interval_secs: u64,
    embedder: Box<dyn embed::TextEmbedder>,
}

// The async maintenance worker (`mindleak-mcp`) moves a `MindLeak` into
// `std::thread::spawn`, so `MindLeak` must stay `Send`. This fails to compile if
// a field regresses that (e.g. a non-thread-safe embedder) — the `Send + Sync`
// bound on `embed::TextEmbedder` is what keeps the boxed embedder `Send`.
const _: fn() = || {
    fn assert_send<T: Send>() {}
    assert_send::<MindLeak>();
};

impl MindLeak {
    /// Open (or create) a MindLeak database at `path`.
    pub fn open(path: &str) -> Result<Self> {
        Ok(MindLeak {
            store: GraphStore::new(db::open(path)?),
            consolidation_min_interval_secs: DEFAULT_CONSOLIDATION_MIN_INTERVAL_SECS,
            embedder: Box::new(embed::Embedder::default()),
        })
    }

    /// Open an ephemeral in-memory graph (tests / tooling).
    pub fn open_in_memory() -> Result<Self> {
        Ok(MindLeak {
            store: GraphStore::new(db::open_in_memory()?),
            consolidation_min_interval_secs: DEFAULT_CONSOLIDATION_MIN_INTERVAL_SECS,
            embedder: Box::new(embed::Embedder::default()),
        })
    }

    /// Override the immutable decay policy resolved by the hosting process.
    pub fn with_decay_policy(mut self, decay_policy: config::DecayPolicy) -> Self {
        self.store = self.store.with_decay_policy(decay_policy);
        self
    }

    pub fn with_working_set_size(mut self, size: usize) -> Self {
        self.store = self.store.with_working_set_size(size);
        self
    }

    pub fn with_consolidation_min_interval(mut self, seconds: u64) -> Self {
        self.consolidation_min_interval_secs = seconds.clamp(60, 86_400);
        self
    }

    /// Override the semantic-recall embedding backend (ADR-0008). Defaults to a
    /// local `/v1/embeddings` client; tests inject a deterministic or unreachable
    /// embedder so the index→recall→seed path is exercised without a live model.
    pub fn with_embedder(mut self, embedder: Box<dyn embed::TextEmbedder>) -> Self {
        self.embedder = embedder;
        self
    }

    pub fn store(&self) -> &GraphStore {
        &self.store
    }
}

